# Category: command_injection

class ImageProcessingController < ApplicationController
  def convert_image
    uploaded_image = params[:image]
    format = params[:format]
    size = params[:size]

    converted_image_path = Rails.root.join('public', 'uploads', "#{SecureRandom.hex}.#{format}")

    system("convert #{uploaded_image.tempfile.path} -resize #{size} #{converted_image_path}")

    send_file converted_image_path
  end
end